package org.example.security;
import org.example.model.entity.User; import org.springframework.security.core.*; import org.springframework.security.core.authority.SimpleGrantedAuthority; import org.springframework.security.core.userdetails.UserDetails; import java.util.*;
public class CustomUserDetails implements UserDetails { private final User user; public CustomUserDetails(User user){this.user=user;} public Collection<? extends GrantedAuthority> getAuthorities(){return List.of(new SimpleGrantedAuthority(user.getRole().name()));} public String getPassword(){return user.getPassword();} public String getUsername(){return user.getEmail();} public boolean isAccountNonExpired(){return true;} public boolean isAccountNonLocked(){return true;} public boolean isCredentialsNonExpired(){return true;} public boolean isEnabled(){return true;} public User getUser(){return user;} }
